/**
 * Configuration module for Voynich physical page position visualizer.
 * 
 * Transcription config (char ordering, display mappings, etc.) is loaded from
 * docs/output/transcription_config.json - the single source of truth generated by
 * the Python processing scripts.
 */

const Config = (function() {
  
  // These will be populated from transcription_config.json
  let CHAR_DISPLAY = {};
  let CHAR_ORDER = [];
  let AGGREGATION_DEFINITIONS = {};
  let _configLoaded = false;
  
  /**
   * Load transcription config from JSON (called by DataLoader on init).
   * @param {Object} config - Config object from transcription_config.json
   */
  function loadTranscriptionConfig(config) {
    // Character display mappings
    CHAR_DISPLAY = config.char_display || {};
    
    // Character ordering (without boundaries for this viz)
    CHAR_ORDER = config.char_order || [];
    
    // Aggregation definitions
    AGGREGATION_DEFINITIONS = config.aggregations || {};
    
    _configLoaded = true;
  }
  
  /**
   * Check if config has been loaded.
   */
  function isConfigLoaded() {
    return _configLoaded;
  }
  
  // Grid resolution display names
  const RESOLUTION_DISPLAY = {
    'coarse': 'Coarse (10×15)',
    'fine': 'Fine (20×30)',
    'raw': 'Raw (100×150)',
  };
  
  // Normalization mode display names
  const NORMALIZATION_DISPLAY = {
    'page': 'Page-relative',
    'manuscript': 'Manuscript-relative',
  };
  
  // Color scales for heatmap
  const COLOR_SCALES = {
    // Heat (white-yellow-red)
    heat: {
      name: 'Heat',
      stops: [
        { pos: 0.0, color: [255, 255, 255] },
        { pos: 0.3, color: [255, 255, 178] },
        { pos: 0.5, color: [254, 204, 92] },
        { pos: 0.7, color: [253, 141, 60] },
        { pos: 0.85, color: [240, 59, 32] },
        { pos: 1.0, color: [189, 0, 38] },
      ],
    },
    // Viridis-like
    viridis: {
      name: 'Viridis',
      stops: [
        { pos: 0.0, color: [253, 231, 37] },
        { pos: 0.25, color: [94, 201, 98] },
        { pos: 0.5, color: [33, 145, 140] },
        { pos: 0.75, color: [59, 82, 139] },
        { pos: 1.0, color: [68, 1, 84] },
      ],
    },
    // Blue to red sequential
    blueRed: {
      name: 'Blue-Red',
      stops: [
        { pos: 0.0, color: [248, 248, 255] },
        { pos: 0.2, color: [198, 219, 239] },
        { pos: 0.4, color: [107, 174, 214] },
        { pos: 0.6, color: [253, 141, 60] },
        { pos: 0.8, color: [227, 74, 51] },
        { pos: 1.0, color: [179, 0, 0] },
      ],
    },
    // Simple grayscale
    grayscale: {
      name: 'Grayscale',
      stops: [
        { pos: 0.0, color: [255, 255, 255] },
        { pos: 1.0, color: [20, 20, 20] },
      ],
    },
  };
  
  // Diverging color scale for diff mode
  const DIFF_COLOR_SCALE = {
    name: 'Diverging (Blue-White-Red)',
    stops: [
      { pos: 0.0, color: [33, 102, 172] },
      { pos: 0.25, color: [103, 169, 207] },
      { pos: 0.45, color: [209, 229, 240] },
      { pos: 0.5, color: [247, 247, 247] },
      { pos: 0.55, color: [253, 219, 199] },
      { pos: 0.75, color: [239, 138, 98] },
      { pos: 1.0, color: [178, 24, 43] },
    ],
  };
  
  // Default settings
  const DEFAULTS = {
    aggregation: 'all',
    resolution: 'coarse',
    useVoynichFont: true,
    colorScale: 'heat',
    cellSize: 30,
    selectedChar: 'o',
  };
  
  /**
   * Get display label for a character.
   * @param {string} char - Internal character code
   * @param {boolean} useVoynichFont - If true, return raw char for font rendering
   * @returns {string} Display label
   */
  function getCharDisplay(char, useVoynichFont = false) {
    if (useVoynichFont) {
      // For Voynich font, expand numbers back to repeated i/e
      const fontMap = {
        '1': 'i', '2': 'ii', '3': 'iii', '4': 'iiii',
        '6': 'e', '7': 'ee', '8': 'eee', '9': 'eeee',
        'C': 'ch', 'S': 'sh', 'T': 'cth', 'P': 'cph', 'F': 'cfh', 'K': 'ckh',
      };
      return fontMap[char] || char;
    }
    
    // Check display mappings
    if (CHAR_DISPLAY[char]) {
      return CHAR_DISPLAY[char];
    }
    
    return char;
  }
  
  /**
   * Get region label for a grid position.
   * Dynamically generates labels based on grid dimensions.
   * @param {number} col - Column index
   * @param {number} row - Row index
   * @param {number} totalCols - Total columns
   * @param {number} totalRows - Total rows
   * @returns {string} Region description
   */
  function getRegionLabel(col, row, totalCols, totalRows) {
    // Horizontal position
    const xPct = col / (totalCols - 1);
    let xLabel;
    if (xPct <= 0.2) xLabel = 'Left';
    else if (xPct <= 0.4) xLabel = 'Center-Left';
    else if (xPct <= 0.6) xLabel = 'Center';
    else if (xPct <= 0.8) xLabel = 'Center-Right';
    else xLabel = 'Right';
    
    // Vertical position
    const yPct = row / (totalRows - 1);
    let yLabel;
    if (yPct <= 0.2) yLabel = 'Top';
    else if (yPct <= 0.4) yLabel = 'Upper';
    else if (yPct <= 0.6) yLabel = 'Middle';
    else if (yPct <= 0.8) yLabel = 'Lower';
    else yLabel = 'Bottom';
    
    return `${yLabel}, ${xLabel}`;
  }
  
  /**
   * Sort characters according to preferred order.
   * @param {string[]} chars - Array of characters
   * @returns {string[]} Sorted array
   */
  function sortCharacters(chars) {
    const orderMap = new Map(CHAR_ORDER.map((c, i) => [c, i]));
    return [...chars].sort((a, b) => {
      const aIdx = orderMap.has(a) ? orderMap.get(a) : 999;
      const bIdx = orderMap.has(b) ? orderMap.get(b) : 999;
      return aIdx - bIdx;
    });
  }
  
  /**
   * Interpolate between color stops to get color for a value.
   * @param {number} value - Value between 0 and 1
   * @param {string} scaleName - Name of color scale to use
   * @returns {string} CSS rgb() color string
   */
  function getColor(value, scaleName = 'heat') {
    const scale = COLOR_SCALES[scaleName] || COLOR_SCALES.heat;
    const stops = scale.stops;
    
    value = Math.max(0, Math.min(1, value));
    
    let lower = stops[0];
    let upper = stops[stops.length - 1];
    
    for (let i = 0; i < stops.length - 1; i++) {
      if (value >= stops[i].pos && value <= stops[i + 1].pos) {
        lower = stops[i];
        upper = stops[i + 1];
        break;
      }
    }
    
    const range = upper.pos - lower.pos;
    const t = range > 0 ? (value - lower.pos) / range : 0;
    
    const r = Math.round(lower.color[0] + t * (upper.color[0] - lower.color[0]));
    const g = Math.round(lower.color[1] + t * (upper.color[1] - lower.color[1]));
    const b = Math.round(lower.color[2] + t * (upper.color[2] - lower.color[2]));
    
    return `rgb(${r}, ${g}, ${b})`;
  }
  
  /**
   * Get color for diff mode (diverging scale).
   * @param {number} value - Normalized diff value (-1 to 1)
   * @returns {string} CSS rgb() color string
   */
  function getDiffColor(value) {
    const normalized = (value + 1) / 2;
    const stops = DIFF_COLOR_SCALE.stops;
    const clampedValue = Math.max(0, Math.min(1, normalized));
    
    let lower = stops[0];
    let upper = stops[stops.length - 1];
    
    for (let i = 0; i < stops.length - 1; i++) {
      if (clampedValue >= stops[i].pos && clampedValue <= stops[i + 1].pos) {
        lower = stops[i];
        upper = stops[i + 1];
        break;
      }
    }
    
    const range = upper.pos - lower.pos;
    const t = range > 0 ? (clampedValue - lower.pos) / range : 0;
    
    const r = Math.round(lower.color[0] + t * (upper.color[0] - lower.color[0]));
    const g = Math.round(lower.color[1] + t * (upper.color[1] - lower.color[1]));
    const b = Math.round(lower.color[2] + t * (upper.color[2] - lower.color[2]));
    
    return `rgb(${r}, ${g}, ${b})`;
  }
  
  // Public API
  return {
    get CHAR_DISPLAY() { return CHAR_DISPLAY; },
    get CHAR_ORDER() { return CHAR_ORDER; },
    get AGGREGATION_DEFINITIONS() { return AGGREGATION_DEFINITIONS; },
    COLOR_SCALES,
    DIFF_COLOR_SCALE,
    DEFAULTS,
    RESOLUTION_DISPLAY,
    NORMALIZATION_DISPLAY,
    loadTranscriptionConfig,
    isConfigLoaded,
    getCharDisplay,
    getRegionLabel,
    sortCharacters,
    getColor,
    getDiffColor,
  };
})();
